import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Dynamically allocate buffer based on user input size
        byte[] buffer = new byte[name.length()];

        // Copy user input into the buffer
        byte[] userInputBytes = name.getBytes();

        // Perform bounds checking to prevent buffer overflow
        int copyLength = Math.min(userInputBytes.length, buffer.length);
        System.arraycopy(userInputBytes, 0, buffer, 0, copyLength);

        System.out.println("Hello, " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
